    [DataRow("Smith", "Mr.", "Dear Mr. Smith,")]
    [DataRow("Johnson", "Dr.", "Dear Dr. Johnson,")]
    [DataRow("Lee", "Ms.", "Dear Ms. Lee,")]
    public void BuildGreeting_VariousTitles_ReturnsExpectedGreeting(string name, string title, string expected)
    {
        var result = _formatter.BuildGreeting(name, title);

        Assert.AreEqual(expected, result);
    }

    [TestMethod]
    public void BuildGreeting_NullName_ThrowsArgumentException()
    {
        Assert.ThrowsExactly<ArgumentNullException>(() => _formatter.BuildGreeting(null!));
    }

    [TestMethod]
    [DataRow("")]
    [DataRow("   ")]
    public void BuildGreeting_EmptyOrWhitespaceName_ThrowsArgumentException(string name)
    {
        Assert.ThrowsExactly<ArgumentException>(() => _formatter.BuildGreeting(name));
    }

    // --- GenerateSlug ---

    [TestMethod]
    public void GenerateSlug_SimpleTitle_ReturnsLowercaseHyphenated()
    {
        var result = _formatter.GenerateSlug("Hello World");

        Assert.AreEqual("hello-world", result);
    }

    [TestMethod]
    public void GenerateSlug_TitleWithSpecialChars_MatchesSlugPattern()
    {
        var result = _formatter.GenerateSlug("My Blog Post! (2024)");

        Assert.MatchesRegex(@"^[a-z0-9]+(-[a-z0-9]+)*$", result);
    }

    [TestMethod]
    public void GenerateSlug_TitleStartingWithWord_StartsWithExpectedWord()
    {
        var result = _formatter.GenerateSlug("Getting Started with C#");

        Assert.StartsWith("getting", result);
    }

    [TestMethod]
    public void GenerateSlug_TitleEndingWithWord_EndsWithExpectedWord()
    {
        var result = _formatter.GenerateSlug("Getting Started with C#");

        // Special chars are replaced; trailing hyphens trimmed
        Assert.EndsWith("c", result);
    }

    [TestMethod]
    [DataRow("  Leading Spaces  ", "leading-spaces")]
    [DataRow("Multiple   Spaces", "multiple-spaces")]
    [DataRow("Special!@#Characters", "special-characters")]
    public void GenerateSlug_VariousInputs_ReturnsExpectedSlug(string title, string expected)
    {
        var result = _formatter.GenerateSlug(title);

        Assert.AreEqual(expected, result);
    }

    [TestMethod]
    public void GenerateSlug_WhitespaceInput_ThrowsArgumentException()
    {
        Assert.ThrowsExactly<ArgumentException>(() => _formatter.GenerateSlug("   "));
    }

    // --- FormatCurrency ---

    [TestMethod]
    public void FormatCurrency_DefaultSymbol_StartsWithDollarSign()
    {
        var result = _formatter.FormatCurrency(19.99m);

        Assert.StartsWith("$", result);
    }

    [TestMethod]
    public void FormatCurrency_EuroSymbol_StartsWithEuro()
    {
        var result = _formatter.FormatCurrency(42.50m, "€");

        Assert.StartsWith("€", result);
    }

    [TestMethod]
    public void FormatCurrency_WholeNumber_EndsWithTwoDecimalZeros()
    {
        var result = _formatter.FormatCurrency(100m);

        Assert.EndsWith(".00", result);
    }

    [TestMethod]
    public void FormatCurrency_TwoDecimalPlaces_MatchesPattern()
    {
        var result = _formatter.FormatCurrency(1234.56m);

        Assert.MatchesRegex(@"^\$\d+\.\d{2}$", result);
    }

    [TestMethod]
    [DataRow(19.99, "$", "$19.99")]
    [DataRow(0.5, "€", "€0.50")]
    [DataRow(1000, "£", "£1000.00")]
    public void FormatCurrency_VariousInputs_ReturnsExpectedFormat(double amount, string symbol, string expected)
    {
        var result = _formatter.FormatCurrency((decimal)amount, symbol);

        Assert.AreEqual(expected, result);
    }
}

